import React from 'react';
import { useTreeContext } from './hooks/TreeContext';
import { useTreeNodeContext } from './hooks/TreeNodeContext';

export const TreeNodeIndents: React.FC = () => {
  const { rootCssScope } = useTreeContext();
  const {
    doublyTreeNode: { depth },
  } = useTreeNodeContext();
  return (
    <>
      {Array(depth - 1)
        .fill(0)
        .map((_, index) => (
          <span className={rootCssScope('__node__indent')} key={index} />
        ))}
    </>
  );
};
